body {
  margin: 0;
  font-family: Inter, Arial, sans-serif;
  color: #111827;
  background: #f3f4f6;
}

.page {
  min-height: 100vh;
  padding: 12px;
}

.print-button {
  width: 100%;
  max-width: 360px;
  height: 40px;
  margin: 0 auto 12px;
  display: block;
  border: 0;
  border-radius: 6px;
  background: #111827;
  color: white;
  font-size: 14px;
  font-weight: 700;
  cursor: pointer;
}

.receipt {
  width: 320px;
  margin: 0 auto;
  padding: 14px;
  background: #fff;
  border: 1px solid #e5e7eb;
  border-radius: 8px;
  font-size: 12px;
  box-shadow: 0 10px 30px rgba(15, 23, 42, 0.12);
}

.top {
  text-align: center;
}

.logo {
  max-width: 150px;
  max-height: 64px;
  object-fit: contain;
  margin-bottom: 8px;
}

h1 {
  margin: 0 0 6px;
  font-size: 17px;
  line-height: 1.2;
}

.company-details {
  color: #4b5563;
  line-height: 1.35;
}

.divider {
  border-top: 1px dashed #9ca3af;
  margin: 12px 0;
}

.receipt-title {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 8px;
}

.receipt-title span {
  display: block;
  color: #6b7280;
  font-size: 11px;
  text-transform: uppercase;
}

.receipt-title strong {
  display: block;
  margin-top: 2px;
  font-size: 15px;
}

.status {
  padding: 4px 7px;
  border-radius: 999px;
  background: #ecfdf5;
  color: #047857;
  font-size: 10px;
  font-weight: 800;
}

.info-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 8px 10px;
}

.info-grid label,
.partner-box label,
.note label,
.fiscal label {
  display: block;
  color: #6b7280;
  font-size: 10px;
  text-transform: uppercase;
  margin-bottom: 2px;
}

.info-grid span {
  font-weight: 600;
}

.partner-box {
  padding: 8px;
  border-radius: 6px;
  background: #f9fafb;
}

.partner-box strong,
.partner-box span {
  display: block;
}

table {
  width: 100%;
  border-collapse: collapse;
}

th {
  text-align: left;
  color: #6b7280;
  font-size: 10px;
  text-transform: uppercase;
  padding-bottom: 5px;
  border-bottom: 1px solid #e5e7eb;
}

td {
  padding: 7px 0;
  vertical-align: top;
  border-bottom: 1px solid #f3f4f6;
}

td strong {
  display: block;
  font-weight: 700;
}

small {
  display: block;
  color: #6b7280;
  margin-top: 2px;
}

.num {
  text-align: right;
  white-space: nowrap;
}

.totals div {
  display: flex;
  justify-content: space-between;
  gap: 12px;
  margin: 5px 0;
}

.totals span {
  color: #4b5563;
}

.totals .grand {
  padding-top: 8px;
  margin-top: 8px;
  border-top: 2px solid #111827;
  font-size: 16px;
}

.note {
  padding: 8px;
  border-radius: 6px;
  background: #fffbeb;
  color: #92400e;
}

.fiscal {
  font-size: 10px;
  line-height: 1.35;
  word-break: break-all;
}

.fiscal div + div {
  margin-top: 6px;
}

.fiscal span {
  font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace;
}

.qr-section {
  margin-top: 12px;
  text-align: center;
}

.qr {
  width: 120px;
  height: 120px;
}

.qr-section div {
  margin-top: 4px;
  color: #6b7280;
  font-size: 10px;
}

.footer {
  margin-top: 14px;
  text-align: center;
}

.footer strong,
.footer span {
  display: block;
}

.footer span {
  margin-top: 4px;
  color: #6b7280;
  font-size: 10px;
}

.empty {
  padding: 24px;
  text-align: center;
  color: #6b7280;
  background: white;
  border-radius: 8px;
}

@media print {
  body {
    background: #fff;
  }
  .page {
    padding: 0;
  }
  .receipt {
    width: 80mm;
    margin: 0;
    padding: 4mm;
    border: 0;
    border-radius: 0;
    box-shadow: none;
  }
  .no-print {
    display: none !important;
  }
}

