            )}
            {header.companyTaxNumber && <div>Tax No: {header.companyTaxNumber}</div>}
            {header.companyRegistrationNumber && <div>Reg No: {header.companyRegistrationNumber}</div>}
            {header.companyEmail && <div>{header.companyEmail}</div>}
            {header.companyPhone && <div>{header.companyPhone}</div>}
          </div>
        </div>

        <div className="divider" />

        <div className="receipt-title">
          <div>
            <span>POS Receipt</span>
            <strong>{header.documentNumber}</strong>
          </div>
          <div className="status">{header.status || "POSTED"}</div>
        </div>

        <div className="info-grid">
          <div>
            <label>Date</label>
            <span>{formatDate(header.documentDate)}</span>
          </div>
          <div>
            <label>Created</label>
            <span>{formatDateTime(header.createdAt)}</span>
          </div>
          <div>
            <label>Warehouse</label>
            <span>{header.warehouseName || "-"}</span>
          </div>
          <div>
            <label>Cashier</label>
            <span>{header.cashier || header.createdBy || "-"}</span>
          </div>
          <div>
            <label>Payment</label>
            <span>{header.paymentMethod || "-"}</span>
          </div>
          {header.cardType && (
            <div>
              <label>Card Type</label>
              <span>{header.cardType}</span>
            </div>
          )}
        </div>

        {(header.partnerName || header.customerName || header.partnerCode) && (
          <>
            <div className="divider" />
            <div className="partner-box">
              <label>Customer</label>
              <strong>{header.partnerName || header.customerName}</strong>
              {header.partnerCode && <span>{header.partnerCode}</span>}
            </div>
          </>
        )}

        <div className="divider" />

        <table className="items">
          <thead>
            <tr>
              <th>Item</th>
              <th className="num">Qty</th>
              <th className="num">Price</th>
              <th className="num">Total</th>
            </tr>
          </thead>
          <tbody>
            {items.map((item, index) => (
              <tr key={index}>
                <td>
                  <strong>{item.description || item.product || "Item"}</strong>
                  {(item.productCode || item.barcode) && (
                    <small>
                      {item.productCode || ""}
                      {item.productCode && item.barcode ? " / " : ""}
                      {item.barcode || ""}
                    </small>
                  )}
                </td>
                <td className="num">{money(item.quantity)}</td>
                <td className="num">{money(item.unitPrice)}</td>
                <td className="num">{money(item.lineTotal)}</td>
              </tr>
            ))}
          </tbody>
        </table>

        <div className="divider" />

        <div className="totals">
          <div>
            <span>Subtotal</span>
            <strong>{money(header.subtotalAmount)} {header.currencyCode}</strong>
          </div>
          <div>
            <span>Discount</span>
            <strong>{money(header.discountAmount)} {header.currencyCode}</strong>
          </div>
          <div>
            <span>Tax</span>
            <strong>{money(header.taxAmount)} {header.currencyCode}</strong>
          </div>
          <div className="grand">
            <span>Total</span>
            <strong>{money(header.totalAmount)} {header.currencyCode}</strong>
          </div>
          <div>
            <span>Paid</span>
            <strong>{money(header.paidAmount)} {header.currencyCode}</strong>
          </div>
          {Number(header.openAmount || 0) !== 0 && (
            <div>
              <span>Open amount</span>
              <strong>{money(header.openAmount)} {header.currencyCode}</strong>
            </div>
          )}
        </div>

        {taxes.length > 0 && (
          <>
            <div className="divider" />
            <table className="taxes">
              <thead>
                <tr>
                  <th>Tax %</th>
                  <th className="num">Base</th>
                  <th className="num">Tax</th>
                  <th className="num">Total</th>
                </tr>
              </thead>
              <tbody>
                {taxes.map((tax, index) => (
                  <tr key={index}>
                    <td>{money(tax.taxRate)}%</td>
                    <td className="num">{money(tax.taxableAmount)}</td>
                    <td className="num">{money(tax.taxAmount)}</td>
                    <td className="num">{money(tax.totalAmount)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </>
        )}

        {(header.note || header.internalNote) && (
          <>
            <div className="divider" />
            <div className="note">
              <label>Note</label>
              <div>{header.note || header.internalNote}</div>
            </div>
          </>
        )}

        <div className="divider" />

        <div className="fiscal">
          <div>
            <label>ZKI</label>
            <span>{header.zki || "-"}</span>
          </div>
          <div>
            <label>JIR</label>
            <span>{header.jir || "-"}</span>
          </div>
        </div>

        {qrCode && (
          <div className="qr-section">
            <img src={qrCode} className="qr" />
            <div>Scan for receipt verification</div>
          </div>
        )}

        <div className="footer">
          <strong>Thank you for your purchase!</strong>
          <span>Please keep this receipt as proof of purchase.</span>
        </div>
      </div>
    </div>
  );
}

function render() {
  ReactDOM.render(<App />, document.getElementById("root"));
}

appsmith.onReady(() => {
  render();
  appsmith.onModelChange(render);
});
